        end
        weld:Destroy()
        weld2:Remove()
        if tors ~= nil then
            rightshoulderz:Clone().Parent = me.Torso
            leftshoulderz:Clone().Parent = me.Torso
        end
        acting = false
    end
    end)
    doit()
end

