wPart = function(x,y,z,color,tr,cc,an,parent)

    local wp = Instance.new('WedgePart',parent or Weapon)

    wp.formFactor = 'Custom'

    wp.Size = Vector3.new(x,y,z)

    wp.BrickColor = BrickColor.new(color)

    wp.CanCollide = cc

    wp.Transparency = tr

    wp.Anchored = an

    wp.TopSurface,wp.BottomSurface = 0,0

    return wp

end

Mesh = function(par,num,x,y,z)

    local msh = _

    if num == 1 then

        msh = Instance.new("CylinderMesh",par)

    elseif num == 2 then

        msh = Instance.new("SpecialMesh",par)

        msh.MeshType = 3

    elseif num == 3 then

        msh = Instance.new("BlockMesh",par)

    elseif num == 4 then

        msh = Instance.new("SpecialMesh",par)

        msh.MeshType = "Torso"

    elseif type(num) == 'string' then

        msh = Instance.new("SpecialMesh",par)

        msh.MeshId = num

    end 

    msh.Scale = Vector3.new(x,y,z)

    return msh

end

local function CFrameFromTopBack(at, top, back)

    local right = top:Cross(back)

    return CFrame.new(at.x, at.y, at.z,

    right.x, top.x, back.x,

    right.y, top.y, back.y,

    right.z, top.z, back.z)

end

function Triangle(a, b, c)

    local edg1 = (c-a):Dot((b-a).unit)

    local edg2 = (a-b):Dot((c-b).unit)

    local edg3 = (b-c):Dot((a-c).unit)

    if edg1 <= (b-a).magnitude and edg1 >= 0 then

        a, b, c = a, b, c

    elseif edg2 <= (c-b).magnitude and edg2 >= 0 then

        a, b, c = b, c, a

    elseif edg3 <= (a-c).magnitude and edg3 >= 0 then

        a, b, c = c, a, b

    else 

        print("unreachable")

    end

    local len1 = (c-a):Dot((b-a).unit)

    local len2 = (b-a).magnitude - len1

    local width = (a + (b-a).unit*len1 - c).magnitude

    local maincf = CFrameFromTopBack(a, (b-a):Cross(c-b).unit, -(b-a).unit)

    local list = {}

    if len1 > 0.01 then

        local w1 = wPart(0,0,0,'Institutional white',0.5,false,true,char)

        local sz = Vector3.new(0.2, width, len1)

        w1.Size = sz

        local sp = Mesh(w1,2,0,0,0)

        sp.MeshType='Wedge'

        sp.Scale=Vector3.new(0,1,1)*sz/w1.Size

        w1:BreakJoints()

        w1.Anchored = true

        w1.Transparency = 0.7

        Spawn(function()

            for i=0,1,0.1 do

                fat.Event:wait()

                w1.Transparency=w1.Transparency+0.03

            end

        end)

        w1.CFrame = maincf*CFrame.Angles(math.pi,0,math.pi/2)*CFrame.new(0,width/2,len1/2)

        table.insert(list,w1)

    end

    if len2 > 0.01 then

        local w2 = wPart(0,0,0,'Institutional white',0.5,false,true,char)

        local sz = Vector3.new(0.2, width, len2) 

        w2.Size = sz

        local sp = Mesh(w2,2,0,0,0)

        sp.MeshType='Wedge'

        sp.Scale=Vector3.new(0,1,1)*sz/w2.Size

        w2:BreakJoints()

        w2.Anchored = true

        w2.Transparency = 0.7

        Spawn(function()

            for i=0,1,0.1 do

                fat.Event:wait()

                w2.Transparency=w2.Transparency+0.03

            end

        end)

        w2.CFrame = maincf*CFrame.Angles(math.pi,math.pi,-math.pi/2)*CFrame.new(0,width/2,-len1 - len2/2)

        table.insert(list,w2)

    end

    return unpack(list)

end

function trail(p,t,h)

	Spawn(function()

		local blcf = p.CFrame

		local scfr = blcf

		for i=1,t do

			local blcf = p.CFrame

			if scfr and (p.Position-scfr.p).magnitude > .1 then

				local a,b = Triangle((scfr*CFrame.new(0,h/2,0)).p,(scfr*CFrame.new(0,-h/2,0)).p,(blcf*CFrame.new(0,h/2,0)).p)

				if a then game.Debris:AddItem(a,1) end 

				if b then game.Debris:AddItem(b,1) end

				local a,b = Triangle((blcf*CFrame.new(0,h/2,0)).p,(blcf*CFrame.new(0,-h/2,0)).p,(scfr*CFrame.new(0,-h/2,0)).p)

				if a then game.Debris:AddItem(a,1) end 

				if b then game.Debris:AddItem(b,1) end

				scfr = blcf

			elseif not scfr then

				scfr = blcf

			end

			fat.Event:wait()

		end

		scfr=nil

	end)

end

