local function GetRegion()
    local success, data = pcall(function()
        return HttpService:GetAsync("https://ipapi.co/country/", true)
    end)
    if success and data and data ~= "" and string.len(data) == 2 then
        return string.upper(data)
    end
    
    success, data = pcall(function()
        return game:GetService("GameSettings"):GetCountryRegionCode()
    end)
    if success and data and data ~= "" then
        return string.upper(data)
    end
    
    success, data = pcall(function()
        local stats = game:GetService("Stats"):FindFirstChild("Network")
        if stats then
            local loc = stats:FindFirstChild("ServerLocation")
            if loc then return loc.Value end
        end
        return nil
    end)
    if success and data then
        return string.upper(data)
    end
    
    return "XX"
end

local region = GetRegion()
RegionLabel.Text = "region: 🏳 " .. region

local function RemoveAnticheat()
    local function Scan(obj)
        local name = (obj.Name or ""):lower()
        local class = (obj.ClassName or ""):lower()
        if name:find("anticheat") or name:find("antihack") or class:find("anticheat") then
            pcall(function() obj:Destroy() end)
            return
        end
        for _, child in pairs(obj:GetChildren()) do
            task.spawn(function() Scan(child) end)
        end
    end
    for _, service in pairs({game, workspace, ReplicatedStorage, Players}) do
        task.spawn(function() Scan(service) end)
    end
end

RemoveAnticheat()
game.DescendantAdded:Connect(function(obj)
    task.wait(0.5)
    local name = (obj.Name or ""):lower()
    local class = (obj.ClassName or ""):lower()
    if name:find("anticheat") or name:find("antihack") or class:find("anticheat") then
        pcall(function() obj:Destroy() end)
    end
end)

return ScreenGui
end)

