local function GQEFNE_fake_script() -- oldcharsounds.LocalScript 
	local script = Instance.new('LocalScript', oldcharsounds)

	script.Parent.MouseButton1Click:Connect(function()
		if not game:IsLoaded() then
			game.Loaded:Wait()
		end
		wait(1)
		local Players = game:GetService("Players")
		local RunService = game:GetService("RunService")
		repeat wait() until game.Players.LocalPlayer.Character
		local SOUND_DATA = {
			Climbing = {
				SoundId = "rbxasset://sounds/action_footsteps_plastic.mp3",
				Looped = true,
			},
			Died = {
				SoundId = "rbxasset://sounds/uuhhh.mp3",
			},
			FreeFalling = {
				SoundId = "rbxasset://sounds/swoosh.wav",
				Looped = true,
			},
			GettingUp = {
				SoundId = "rbxasset://sounds/hit.wav",
			},
			Jumping = {
				SoundId = "rbxasset://sounds/button.wav",
			},
			Landing = {
				SoundId = "rbxasset://sounds/action_jump_land.mp3",
			},
			Splash = {
				SoundId = "rbxasset://sounds/impact_water.mp3",
			},
			Swimming = {
				SoundId = "rbxasset://sounds/action_swim.mp3",
				Looped = true,
				Pitch = 1.6,
			},
		}
	
		-- wait for the first of the passed signals to fire
		local function waitForFirst(...)
			local shunt = Instance.new("BindableEvent")
			local slots = {...}
	
			local function fire(...)
				for i = 1, #slots do
					slots[i]:Disconnect()
				end
	
				return shunt:Fire(...)
			end
	
			for i = 1, #slots do
				slots[i] = slots[i]:Connect(fire)
			end
	
			return shunt.Event:Wait()
		end
	
		-- map a value from one range to another
		local function map(x, inMin, inMax, outMin, outMax)
			return (x - inMin)*(outMax - outMin)/(inMax - inMin) + outMin
		end
	
		local function playSound(sound)
			sound.TimePosition = 0
			sound.Playing = true
		end
	
		local function shallowCopy(t)
			local out = {}
			for k, v in pairs(t) do
				out[k] = v
			end
			return out
		end
	
		local function initializeSoundSystem(player, humanoid, rootPart)
			local sounds = {}
	
			-- initialize sounds
			for name, props in pairs(SOUND_DATA) do
				local sound = Instance.new("Sound")
				sound.Name = name
	
				-- set default values
				sound.Archivable = false
				sound.EmitterSize = 5
				sound.MaxDistance = 150
				sound.Volume = 0.65
	
				for propName, propValue in pairs(props) do
					sound[propName] = propValue
				end
	
				sound.Parent = rootPart
				sounds[name] = sound
			end
	
			local playingLoopedSounds = {}
	
			local function stopPlayingLoopedSounds(except)
				for sound in pairs(shallowCopy(playingLoopedSounds)) do
					if sound ~= except then
						sound.Playing = false
						playingLoopedSounds[sound] = nil
					end
				end
			end
	
			-- state transition callbacks
			local stateTransitions = {
				[Enum.HumanoidStateType.FallingDown] = function()
					stopPlayingLoopedSounds()
				end,
	
				[Enum.HumanoidStateType.GettingUp] = function()
					stopPlayingLoopedSounds()
					playSound(sounds.GettingUp)
				end,
	
				[Enum.HumanoidStateType.Jumping] = function()
					stopPlayingLoopedSounds()
					playSound(sounds.Jumping)
				end,
	
				[Enum.HumanoidStateType.Swimming] = function()
					local verticalSpeed = math.abs(rootPart.Velocity.Y)
					if verticalSpeed > 0.1 then
						sounds.Splash.Volume = math.clamp(map(verticalSpeed, 100, 350, 0.28, 1), 0, 1)
						playSound(sounds.Splash)
					end
					stopPlayingLoopedSounds(sounds.Swimming)
					sounds.Swimming.Playing = true
					playingLoopedSounds[sounds.Swimming] = true
				end,
	
				[Enum.HumanoidStateType.Freefall] = function()
					sounds.FreeFalling.Volume = 0
					stopPlayingLoopedSounds(sounds.FreeFalling)
					playingLoopedSounds[sounds.FreeFalling] = true
				end,
	
				[Enum.HumanoidStateType.Landed] = function()
					stopPlayingLoopedSounds()
					local verticalSpeed = math.abs(rootPart.Velocity.Y)
					if verticalSpeed > 75 then
						sounds.Landing.Volume = math.clamp(map(verticalSpeed, 50, 100, 0, 1), 0, 1)
						playSound(sounds.Landing)
					end
				end,
	
				[Enum.HumanoidStateType.Climbing] = function()
					local sound = sounds.Climbing
					if math.abs(rootPart.Velocity.Y) > 0.1 then
						sound.Playing = true
						stopPlayingLoopedSounds(sound)
					else
						stopPlayingLoopedSounds()
					end
					playingLoopedSounds[sound] = true
				end,
	
				[Enum.HumanoidStateType.Seated] = function()
					stopPlayingLoopedSounds()
				end,
	
				[Enum.HumanoidStateType.Dead] = function()
					stopPlayingLoopedSounds()
					playSound(sounds.Died)
				end,
			}
	
			-- updaters for looped sounds
			local loopedSoundUpdaters = {
				[sounds.Climbing] = function(dt, sound, vel)
					sound.Playing = vel.Magnitude > 0.1
				end,
	
				[sounds.FreeFalling] = function(dt, sound, vel)
					if vel.Magnitude > 75 then
						sound.Volume = math.clamp(sound.Volume + 0.9*dt, 0, 1)
					else
						sound.Volume = 0
					end
				end,
	
	
			}
	
			-- state substitutions to avoid duplicating entries in the state table
			local stateRemap = {
				[Enum.HumanoidStateType.RunningNoPhysics] = Enum.HumanoidStateType.Running,
			}
	
			local activeState = stateRemap[humanoid:GetState()] or humanoid:GetState()
	
			local stateChangedConn = humanoid.StateChanged:Connect(function(_, state)
				state = stateRemap[state] or state
	
				if state ~= activeState then
					local transitionFunc = stateTransitions[state]
	
					if transitionFunc then
						transitionFunc()
					end
	
					activeState = state
				end
			end)
	
			local steppedConn = RunService.Stepped:Connect(function(_, worldDt)
				-- update looped sounds on stepped
				for sound in pairs(playingLoopedSounds) do
					local updater = loopedSoundUpdaters[sound]
	
					if updater then
						updater(worldDt, sound, rootPart.Velocity)
					end
				end
			end)
	
			local humanoidAncestryChangedConn
			local rootPartAncestryChangedConn
			local characterAddedConn
	
			local function terminate()
				stateChangedConn:Disconnect()
				steppedConn:Disconnect()
				humanoidAncestryChangedConn:Disconnect()
				rootPartAncestryChangedConn:Disconnect()
				characterAddedConn:Disconnect()
			end
	
			humanoidAncestryChangedConn = humanoid.AncestryChanged:Connect(function(_, parent)
				if not parent then
					terminate()
				end
			end)
	
			rootPartAncestryChangedConn = rootPart.AncestryChanged:Connect(function(_, parent)
				if not parent then
					terminate()
				end
			end)
	
			characterAddedConn = player.CharacterAdded:Connect(terminate)
		end
	
		local function playerAdded(player)
			local function characterAdded(character)
				-- Avoiding memory leaks in the face of Character/Humanoid/RootPart lifetime has a few complications:
				-- * character deparenting is a Remove instead of a Destroy, so signals are not cleaned up automatically.
				-- ** must use a waitForFirst on everything and listen for hierarchy changes.
				-- * the character might not be in the dm by the time CharacterAdded fires
				-- ** constantly check consistency with player.Character and abort if CharacterAdded is fired again
				-- * Humanoid may not exist immediately, and by the time it's inserted the character might be deparented.
				-- * RootPart probably won't exist immediately.
				-- ** by the time RootPart is inserted and Humanoid.RootPart is set, the character or the humanoid might be deparented.
	
				if not character.Parent then
					waitForFirst(character.AncestryChanged, player.CharacterAdded)
				end
	
				if player.Character ~= character or not character.Parent then
					return
				end
	
				local humanoid = character:FindFirstChildOfClass("Humanoid")
				while character:IsDescendantOf(game) and not humanoid do
					waitForFirst(character.ChildAdded, character.AncestryChanged, player.CharacterAdded)
					humanoid = character:FindFirstChildOfClass("Humanoid")
				end
	
				if player.Character ~= character or not character:IsDescendantOf(game) then
					return
				end
	
				-- must rely on HumanoidRootPart naming because Humanoid.RootPart does not fire changed signals
				local rootPart = character:FindFirstChild("HumanoidRootPart")
				while character:IsDescendantOf(game) and not rootPart do
					waitForFirst(character.ChildAdded, character.AncestryChanged, humanoid.AncestryChanged, player.CharacterAdded)
					rootPart = character:FindFirstChild("HumanoidRootPart")
				end
	
				if rootPart and humanoid:IsDescendantOf(game) and character:IsDescendantOf(game) and player.Character == character then
					initializeSoundSystem(player, humanoid, rootPart)
				end
			end
	
			if player.Character then
				characterAdded(player.Character)
			end
			player.CharacterAdded:Connect(characterAdded)
		end
	
		Players.PlayerAdded:Connect(playerAdded)
		for _, player in ipairs(Players:GetPlayers()) do
			playerAdded(player)
		end
	
		end)
end
coroutine.wrap(GQEFNE_fake_script)()
local function EJAJAVZ_fake_script() -- oldanim.LocalScript 
	local script = Instance.new('LocalScript', oldanim)

	script.Parent.MouseButton1Click:Connect(function()
		if game.PlaceId == 445664957 then
			return;
		end
	
		local player = game:GetService("Players").LocalPlayer
		repeat wait() until game.Players.LocalPlayer.Character
		Char = game.Players.LocalPlayer.Character or player.CharacterAdded:Wait()
	
	
		if Char.Humanoid.RigType == Enum.HumanoidRigType.R6 == true then
	
			game.Players.LocalPlayer.Character:BreakJoints()
			game.Players.LocalPlayer.Character=nil
			Connection = game.Workspace.DescendantAdded:Connect(function(c)
				if c.Name == "Animate" then
					c.Disabled=true        
				end
			end)
	
			function waitForChild(parent, childName)
				local child = parent:findFirstChild(childName)
				if child then return child end
				while true do
					child = parent.ChildAdded:wait()
					if child.Name==childName then return child end
				end
			end
	
			repeat wait() until game:GetService("Players").LocalPlayer.Character ~= nil and game:GetService("Players").LocalPlayer.Character:FindFirstChild("Humanoid") ~= nil
	
			Died = game.Players.LocalPlayer.Character:waitForChild("Humanoid").Died:Connect(function()
				Connection:Disconnect()
				Died:Disconnect()
			end)
			wait(.1)
	
			-- ANIMATION
	
			-- declarations
	
			local Figure = game.Players.LocalPlayer.Character
			local Torso = waitForChild(Figure, "Torso")
			local RightShoulder = waitForChild(Torso, "Right Shoulder")
			local LeftShoulder = waitForChild(Torso, "Left Shoulder")
			local RightHip = waitForChild(Torso, "Right Hip")
			local LeftHip = waitForChild(Torso, "Left Hip")
			local Neck = waitForChild(Torso, "Neck")
			local Humanoid = waitForChild(Figure, "Humanoid")
			local pose = "Standing"
	
			local toolAnim = "None"
			local toolAnimTime = 0
	
			local jumpMaxLimbVelocity = 0.75
	
			-- functions
	
			function onRunning(speed)
				if speed>0 then
					pose = "Running"
				else
					pose = "Standing"
				end
			end
	
			function onDied()
				pose = "Dead"
			end
	
			function onJumping()
				pose = "Jumping"
			end
	
			function onClimbing()
				pose = "Climbing"
			end
	
			function onGettingUp()
				pose = "GettingUp"
			end
	
			function onFreeFall()
				pose = "FreeFall"
			end
	
			function onFallingDown()
				pose = "FallingDown"
			end
	
			function onSeated()
				pose = "Seated"
			end
	
			function onPlatformStanding()
				pose = "PlatformStanding"
			end
	
			function onSwimming(speed)
				if speed>0 then
					pose = "Running"
				else
					pose = "Standing"
				end
			end
	
			function moveJump()
				RightShoulder.MaxVelocity = jumpMaxLimbVelocity
				LeftShoulder.MaxVelocity = jumpMaxLimbVelocity
				RightShoulder:SetDesiredAngle(3.14)
				LeftShoulder:SetDesiredAngle(-3.14)
				RightHip:SetDesiredAngle(0)
				LeftHip:SetDesiredAngle(0)
			end
	
	
			-- same as jump for now
	
			function moveFreeFall()
				RightShoulder.MaxVelocity = jumpMaxLimbVelocity
				LeftShoulder.MaxVelocity = jumpMaxLimbVelocity
				RightShoulder:SetDesiredAngle(3.14)
				LeftShoulder:SetDesiredAngle(-3.14)
				RightHip:SetDesiredAngle(0)
				LeftHip:SetDesiredAngle(0)
			end
	
			function moveSit()
				RightShoulder.MaxVelocity = 0.15
				LeftShoulder.MaxVelocity = 0.15
				RightShoulder:SetDesiredAngle(3.14 /2)
				LeftShoulder:SetDesiredAngle(-3.14 /2)
				RightHip:SetDesiredAngle(3.14 /2)
				LeftHip:SetDesiredAngle(-3.14 /2)
			end
	
			function getTool()
				for _, kid in ipairs(Figure:GetChildren()) do
					if kid.className == "Tool" then return kid end
				end
				return nil
			end
	
			function getToolAnim(tool)
				for _, c in ipairs(tool:GetChildren()) do
					if c.Name == "toolanim" and c.className == "StringValue" then
						return c
					end
				end
				return nil
			end
	
			function animateTool()
	
				if (toolAnim == "None") then
					RightShoulder:SetDesiredAngle(1.57)
					return
				end
	
				if (toolAnim == "Slash") then
					RightShoulder.MaxVelocity = 0.5
					RightShoulder:SetDesiredAngle(0)
					return
				end
	
				if (toolAnim == "Lunge") then
					RightShoulder.MaxVelocity = 0.5
					LeftShoulder.MaxVelocity = 0.5
					RightHip.MaxVelocity = 0.5
					LeftHip.MaxVelocity = 0.5
					RightShoulder:SetDesiredAngle(1.57)
					LeftShoulder:SetDesiredAngle(1.0)
					RightHip:SetDesiredAngle(1.57)
					LeftHip:SetDesiredAngle(1.0)
					return
				end
			end
	
			function move(time)
				local amplitude
				local frequency
	
				if (pose == "Jumping") then
					moveJump()
					return
				end
	
				if (pose == "FreeFall") then
					moveFreeFall()
					return
				end
	
				if (pose == "Seated") then
					moveSit()
					return
				end
	
				local climbFudge = 0
	
				if (pose == "Running") then
					if (RightShoulder.CurrentAngle > 1.5 or RightShoulder.CurrentAngle < -1.5) then
						RightShoulder.MaxVelocity = jumpMaxLimbVelocity
					else  
						RightShoulder.MaxVelocity = 0.15
					end
					if (LeftShoulder.CurrentAngle > 1.5 or LeftShoulder.CurrentAngle < -1.5) then
						LeftShoulder.MaxVelocity = jumpMaxLimbVelocity
					else  
						LeftShoulder.MaxVelocity = 0.15
					end
					amplitude = 1
					frequency = 9
				elseif (pose == "Climbing") then
					RightShoulder.MaxVelocity = 0.5
					LeftShoulder.MaxVelocity = 0.5
					amplitude = 1
					frequency = 9
					climbFudge = 3.14
				else
					amplitude = 0.1
					frequency = 1
				end
	
				desiredAngle = amplitude * math.sin(time*frequency)
	
				RightShoulder:SetDesiredAngle(desiredAngle + climbFudge)
				LeftShoulder:SetDesiredAngle(desiredAngle - climbFudge)
				RightHip:SetDesiredAngle(-desiredAngle)
				LeftHip:SetDesiredAngle(-desiredAngle)
	
	
				local tool = getTool()
	
				if tool then
	
					animStringValueObject = getToolAnim(tool)
	
					if animStringValueObject then
						toolAnim = animStringValueObject.Value
						-- message recieved, delete StringValue
						animStringValueObject.Parent = nil
						toolAnimTime = time + .3
					end
	
					if time > toolAnimTime then
						toolAnimTime = 0
						toolAnim = "None"
					end
	
					animateTool()
	
	
				else
					toolAnim = "None"
					toolAnimTime = 0
				end
			end
	
	
			-- connect events
	
			Humanoid.Died:connect(onDied)
			Humanoid.Running:connect(onRunning)
			Humanoid.Jumping:connect(onJumping)
			Humanoid.Climbing:connect(onClimbing)
			Humanoid.GettingUp:connect(onGettingUp)
			Humanoid.FreeFalling:connect(onFreeFall)
			Humanoid.FallingDown:connect(onFallingDown)
			Humanoid.Seated:connect(onSeated)
			Humanoid.PlatformStanding:connect(onPlatformStanding)
			Humanoid.Swimming:connect(onSwimming)
			-- main program
	
			local runService = game:service("RunService");
	
			while Figure.Parent~=nil do
				local _, time = wait(0.1)
				move(time)
			end
		end
		end)
end
