					end
				elseif not new then
					local existingPlayer = nil
	
					for index, player in next, game.Players:GetPlayers() do
						if player.Name:lower() == name:lower() then
							existingPlayer = player
							break
						end
					end
	
	
					if existingPlayer ~= nil then
						RemovePlayerFrame(existingPlayer)
					end
				end
			end
		end
	
