local Players = game:GetService("Players")
local LocalPlayer = Players.LocalPlayer

-- Функция перезахода
local function Rejoin()
    -- Проверяем, существует ли телекоманда
    if Teleport then
        Teleport(game.PlaceId, LocalPlayer)
    else
