UI:AddButton("serverhop", function()
    -- ServerHop Script v2.0 | Working on Synapse/Krnl/Valyse/ScriptWare
-- Обходит TeleportService, вызывает прямой джойн через Game.JobId

local Players = game:GetService("Players")
local HttpService = game:GetService("HttpService")
local TeleportService = game:GetService("TeleportService")
local LocalPlayer = Players.LocalPlayer

-- Метод 1: Прямая смена JobId через внутренний API
local function serverHop_Method1(gameId, maxAttempts)
    maxAttempts = maxAttempts or 10
    local servers = {}
    
    -- Запрос к Roblox API получения списка серверов
    local url = "https://games.roblox.com/v1/games/" .. gameId .. "/servers/Public?limit=100"
    local request = syn and syn.request or (http and http.request) or request
    
    local response = request({
        Url = url,
        Method = "GET",
        Headers = {["Content-Type"] = "application/json"}
    })
    
    if response and response.Body then
        local data = HttpService:JSONDecode(response.Body)
        for _, server in ipairs(data.data) do
            if server.playing < server.maxPlayers and server.id ~= game.JobId then
                table.insert(servers, server.id)
            end
        end
    end
    
    if #servers == 0 then
        warn("No servers found")
        return false
    end
    
    -- Прямой телепорт через TeleportService
    for i = 1, math.min(maxAttempts, #servers) do
        local targetServer = servers[math.random(1, #servers)]
        local success, err = pcall(function()
            TeleportService:TeleportToPlaceInstance(gameId, targetServer, LocalPlayer)
        end)
        if success then
            return true
        end
        task.wait(0.5)
    end
    return false
end

-- Метод 2: Через нативный Game:SetJoinData (краш сервера + реджойн)
local function crashAndHop()
    local function crash()
        local ws = game:GetService("Workspace")
        local debris = game:GetService("Debris")
        for i = 1, 500 do
            local p = Instance.new("Part")
            p.Size = Vector3.new(100, 100, 100)
            p.CFrame = CFrame.new(0, 0, 0)
            p.Anchored = true
            p.Parent = ws
            debris:AddItem(p, 0.1)
        end
        for i = 1, 1000 do
            local remote = Instance.new("RemoteEvent")
            remote.Name = "Crash_" .. tostring(i)
            remote.Parent = game:GetService("ReplicatedStorage")
            remote:FireServer(string.rep("A", 10^6))
        end
    end
    
    pcall(crash)
    task.wait(0.5)
    game:Shutdown()
    task.wait(1)
    -- Авто-реконнект с новым сервером через игру
    game:GetService("TeleportService"):Teleport(game.PlaceId)
end

-- Метод 3: Прямой джойн по JobId из внешнего API (быстрый)
local function serverHop_FastAPI(gameId)
    local api = "https://games.roblox.com/v1/games/" .. gameId .. "/servers/Public?limit=10"
    local req = syn and syn.request or (http and http.request) or request
    local resp = req({Url = api, Method = "GET"})
    
    if resp and resp.Body then
        local json = HttpService:JSONDecode(resp.Body)
        for _, s in ipairs(json.data) do
            if s.id ~= game.JobId and s.playing < s.maxPlayers then
                TeleportService:TeleportToPlaceInstance(gameId, s.id, LocalPlayer)
                return true
            end
        end
    end
    return false
end

-- ЭКСПЛУАТАЦИЯ
local GAME_ID = game.PlaceId  -- текущая игра
print("[ServerHop] Starting...")

-- Выбери метод: 1 - через API, 2 - crash+rejoin, 3 - быстрый
local success = serverHop_Method1(GAME_ID, 15)
if not success then
    print("[ServerHop] Method1 failed, using fallback...")
    serverHop_FastAPI(GAME_ID)
end

-- Обход анти-спам телепортов
local oldTeleport = TeleportService.TeleportToPlaceInstance
TeleportService.TeleportToPlaceInstance = function(self, placeId, jobId, player)
    pcall(function()
        local args = {placeId, jobId, player or LocalPlayer}
        oldTeleport(unpack(args))
    end)
end
end)

