					--end)
					MeshResize(v,Vector3.new(50,50,50))
					SetLocked(v,true)
				end
			end
		end
		Sky(game.Players.LocalPlayer.PlayerGui.CoolGui.settings.smain.sdid.Text)
	
	end)
end
