UI:AddButton("R15 Conventer for WallHop Practicle", function()
    local function deepScan(obj, depth)
    depth = depth or 0
    if depth > 10 then return end
    local found = {}
    for i,v in pairs(obj:GetChildren()) do
        if v:IsA("RemoteEvent") or v:IsA("RemoteFunction") or v:IsA("UnreliableRemoteEvent") then
            table.insert(found, {
                Name = v.Name,
                Class = v.ClassName,
                Parent = v.Parent and v.Parent.Name or "nil",
                Path = getfenv().script:GetFullName() .. "." .. v:GetFullName()
            })
            if v:IsA("RemoteEvent") then
                pcall(function()
                    v:FireServer("SCAN_TRIGGER_" .. tostring(os.time()))
                end)
            end
        end
        for _, sub in ipairs(deepScan(v, depth + 1)) do
            table.insert(found, sub)
        end
    end
    return found
end

local function scanWorkspace()
    local remotes = {}
    for _, service in ipairs({game:GetService("ReplicatedStorage"), 
                               game:GetService("Workspace"), 
                               game:GetService("Players")}) do
        for _, remote in ipairs(deepScan(service)) do
            table.insert(remotes, remote)
        end
    end
    return remotes
end

local results = scanWorkspace()
local output = "REMOTES FOUND: " .. #results .. "\n\n"
for i, r in ipairs(results) do
    output = output .. string.format("[%d] %s (%s)\n    Parent: %s\n    Path: %s\n\n", 
                                     i, r.Name, r.Class, r.Parent, r.Path)
end
if syn and syn.writefile then
    syn.writefile("remote_scan.txt", output)
end
local oldFire = Instance.new("RemoteEvent").FireServer
local meta = getrawmetatable(game)
local oldIndex = meta.__index
setreadonly(meta, false)
meta.__index = function(self, key)
    if key == "FireServer" and self:IsA("RemoteEvent") then
        return function(_, ...)
            local args = {...}
            return oldFire(self, unpack(args))
        end
    end
    return oldIndex(self, key)
end
setreadonly(meta, true)
end)

