			lp.Character.LowerTorso.CanCollide = not Clip

		end

	end)

	lp.Character.HumanoidRootPart.Changed:connect(function()

		topkek.libutil:getTorso(lp).CanCollide = not Clip

		lp.Character.Head.CanCollide = not Clip

