WormDrill = function(target,sca) q(function() local spiran = rn(-360,360) local slope = {} 
for i=90,-270,-10 do table.insert(slope,cn(target.p)*ca(0,rd(spiran),0)*cn(0,0,30*sca)*ca(rd(i),0,0)*cn(0,0,30*sca)) end 
