wait() end FireObj(v,cn(v.Position,v.CFrame*cn(0,0,-2).p),ca(0,0,0),8,20,6,function(h) ProjHit1(v,h,1.2) end,8) end) end for i=1,20 do wait() end local holp = hol.CFrame fade(hol,0.1) 
