    --Credits to Paul Migo & OpTic Wisdom

game:GetObjects("rbxassetid://503182370")[1].Parent=game.Players.LocalPlayer.Backpack

game.Players.LocalPlayer.Backpack.AssaultRifle.Main.Transparency = 0
