--[[DMG]]
function damagesplat(dmg,hit)
    local mo = Instance.new("Model")
    mo.Name = dmg
    local pa = Instance.new("Part",mo)
    pa.formFactor = 3
    pa.Size = Vector3.new(0.8,0.3,0.8)
    pa.BrickColor = BrickColor.new(chosen)
        pa.CanCollide=false
    pa.CFrame = CFrame.new(hit.Position) * CFrame.new(0, 3, 0)
    pa.Name = "Head"
        cm=Instance.new("CylinderMesh",pa)
    local hah = Instance.new("Humanoid")
    hah.Parent = mo
    hah.MaxHealth = 0
    hah.Health = 0
    local bp = Instance.new("BodyPosition")
    bp.P = 14000
    bp.maxForce = Vector3.new(math.huge, math.huge, math.huge)
    bp.position = hit.Position + Vector3.new(0, 5, 0)
    coroutine.resume(coroutine.create(function()
        wait()
        mo.Parent = workspace
        bp.Parent = pa
        wait(1.4)
        mo:remove()
    end))
end
con = nil
con2 = nil
hitd=0
hitd2=0
function OT(hit)
if hit.Parent == nil then return end
local hum = hit.Parent:findFirstChild("Humanoid")
local head = hit.Parent:findFirstChild("Head")
if hum ~= nil then
dm=math.random(10000,10000)
hum:TakeDamage(dm)
if head ~= nil then
damagesplat(dm,head)
end
end
hitd=1
end
function OT2(hit)
if hit.Parent == nil then return end
local hum = hit.Parent:findFirstChild("Humanoid")
local head = hit.Parent:findFirstChild("Head")
if hum ~= nil then
dm=math.random(10000,10000)
hum:TakeDamage(dm)
if head ~= nil then
damagesplat(dm,head)
end
end
hitd2=1
end
function dmgcnnct(p)
con = p.Touched:connect(OT)
end
function dmgcnnct2(p)
con2 = p.Touched:connect(OT2)
end
function dmgdc2()
if con2 ~= nil then
con2:disconnect()
hitd2=0
end
end
function dmgdc()
if con ~= nil then
con:disconnect()
hitd=0
end
end
