		LH.C0=clerp(LH.C0,cf(-1,-1,0)*angles(math.rad(0),math.rad(-90),math.rad(0))*angles(math.rad(-5),math.rad(0),math.rad(25)),.37)
	end
	attack=false
	Humanoid.WalkSpeed=16
	con1:disconnect()
end

